func (s *Storage) Set(key string, val []byte, exp time.Duration) error {

	if len(key) == 0 || len(val) == 0 {
		return nil
	}

	var expire uint32
	if exp != 0 {
		expire = uint32(exp.Seconds()) + utils.Timestamp()
	}

	e := entry{data: val, expiry: expire}
	s.mux.Lock()
	s.db[key] = e
	s.mux.Unlock()
	return nil
}
